<?php
namespace App\Modules\Drivers\Application\Services;
use App\Models\ActivityLog; use App\Models\Driver; use App\Modules\Drivers\Application\StateMachines\DriverShiftStateMachine; use App\Modules\Realtime\Domain\Events\DriverStatusUpdated; use App\Support\Observability\CorrelationContext;
final class DriverShiftService { public function __construct(private readonly DriverShiftStateMachine $states) {} public function startShift(Driver $driver): Driver { return $this->move($driver,DriverShiftStateMachine::AVAILABLE,'driver.shift.started'); } public function endShift(Driver $driver): Driver { return $this->move($driver,DriverShiftStateMachine::FINISHED,'driver.shift.ended',['ended_at'=>now()->toISOString()]); } public function breakShift(Driver $driver): Driver { return $this->move($driver,DriverShiftStateMachine::BREAK,'driver.shift.break'); } public function resumeShift(Driver $driver): Driver { return $this->move($driver,DriverShiftStateMachine::AVAILABLE,'driver.shift.resumed'); } public function currentShift(Driver $driver): array { return ['driver_id'=>$driver->id,'status'=>$driver->status,'metadata'=>$driver->metadata ?? []]; } public function move(Driver $driver,string $to,string $action,array $metadata=[]): Driver { $from=$driver->status ?: DriverShiftStateMachine::OFFLINE; $driver->forceFill(['status'=>$this->states->transition($from,$to),'metadata'=>array_merge($driver->metadata??[],['last_status_at'=>now()->toISOString()])])->save(); ActivityLog::create(['action'=>$action,'subject_type'=>Driver::class,'subject_id'=>$driver->id,'metadata'=>['from'=>$from,'to'=>$to,'driver_uuid'=>$driver->uuid,'correlation_id'=>CorrelationContext::correlationId()]+$metadata]); event(new DriverStatusUpdated((string)$driver->id,$to)); return $driver; }}
